// Private internal module — not exported from the ./icons barrel.
// Import makeIcon and Svg from this file only within src/icons/*.

import { createElement as h } from 'react'

export function Svg({ size, strokeWidth, className, style, title, strokeLinecap, strokeLinejoin, rest }, children) {
  const props = {
    width: size,
    height: size,
    viewBox: '0 0 24 24',
    fill: 'none',
    stroke: 'currentColor',
    strokeWidth,
    strokeLinecap: strokeLinecap || 'round',
    strokeLinejoin: strokeLinejoin || 'round',
    className,
    style,
    role: title ? 'img' : undefined,
    'aria-hidden': title ? undefined : 'true',
    ...rest,
  }
  const kids = title ? [h('title', { key: '__t' }, title), ...children] : children
  return h('svg', props, ...kids)
}

export function makeIcon(paths) {
  return function IconComponent({
    size = 24,
    strokeWidth = 2,
    className,
    style,
    title,
    strokeLinecap,
    strokeLinejoin,
    ...rest
  }) {
    return Svg(
      { size, strokeWidth, className, style, title, strokeLinecap, strokeLinejoin, rest },
      paths.map((p, i) => h(p.tag, { key: i, ...p.attrs }))
    )
  }
}
